const request = $('Build Agent Request').first().json;
const chunks = Array.isArray($input.first().json.chunks) ? $input.first().json.chunks : [];
const contextLines = chunks.map((chunk, index) => {
  const source = chunk.source || chunk.type || 'context';
  const speaker = chunk.speaker || chunk.title || `source ${index + 1}`;
  const text = chunk.text || chunk.content || '';
  return `[${source}] ${speaker}: ${text}`;
}).filter(Boolean);
const sources = chunks.map((chunk, index) => `${chunk.source || chunk.type || 'context'}: ${chunk.speaker || chunk.title || `source ${index + 1}`}`);
return [{ json: { meetingId: request.meetingId, requestText: request.requestText, contextText: contextLines.join('\n'), contextChunks: chunks, sources, hasContext: chunks.length > 0, retrievalError: false } }];

const item = $input.first().json;
const prompt = `Meeting context:
${item.contextText || '(no retrieved context)'}

User request: ${item.requestText}

Return ONLY valid JSON with this shape:
{
  "type": "diagram",
  "text": "short spoken response",
  "diagramCode": "valid Mermaid flowchart TD code",
  "sources": ["source labels used"]
}

Rules:
- Ground the diagram only in the meeting context.
- If the context is insufficient, return type "answer", explain that, set diagramCode to null, and keep sources empty.
- Mermaid must start with flowchart TD and must not be wrapped in backticks.`;
return [{ json: { ...item, prompt } }];

function extractGeminiText(payload) {
  if (!payload) return '';
  if (typeof payload === 'string') return payload;
  if (payload.output) return typeof payload.output === 'string' ? payload.output : JSON.stringify(payload.output);
  if (payload.text) return payload.text;
  const parts = payload.candidates?.[0]?.content?.parts || [];
  return parts.map(part => part.text || '').join('\n').trim();
}

function parseModelJson(text, fallback) {
  const cleaned = String(text || '')
    .replace(/^```(?:json|mermaid)?\s*/i, '')
    .replace(/```$/i, '')
    .trim();
  if (!cleaned) return fallback;
  try {
    return JSON.parse(cleaned);
  } catch (error) {
    const start = cleaned.indexOf('{');
    const end = cleaned.lastIndexOf('}');
    if (start >= 0 && end > start) {
      try { return JSON.parse(cleaned.slice(start, end + 1)); } catch (_) {}
    }
    return { ...fallback, text: cleaned };
  }
}
const sourceItem = $('Build Diagram Prompt').first().json;
const parsed = parseModelJson(extractGeminiText($input.first().json), { type: 'answer', text: 'I could not generate a grounded diagram from the retrieved context.', diagramCode: null, sources: [] });
const diagramCode = parsed.diagramCode ? String(parsed.diagramCode).replace(/^```(?:mermaid)?\s*/i, '').replace(/```$/i, '').trim() : null;
return [{ json: { meetingId: sourceItem.meetingId, type: parsed.type === 'diagram' && diagramCode ? 'diagram' : 'answer', text: parsed.text || 'Diagram generated.', diagramCode, sources: Array.isArray(parsed.sources) && parsed.sources.length ? parsed.sources : sourceItem.sources } }];

const item = $input.first().json;
if (item.type !== 'diagram') return [{ json: item }];
const code = String(item.diagramCode || '').trim();
const validPrefixes = ['flowchart', 'graph', 'sequenceDiagram', 'classDiagram', 'stateDiagram', 'journey', 'erDiagram', 'gantt', 'pie'];
const isValid = validPrefixes.some(prefix => code.startsWith(prefix));
return [{ json: isValid ? { ...item, diagramCode: code } : { meetingId: item.meetingId, type: 'answer', text: 'I generated a response, but the diagram code was not valid Mermaid.', diagramCode: null, sources: item.sources || [] } }];

